<?php
namespace App\Services; use App\Models\{Account,AccountMovement}; use Illuminate\Support\Facades\DB;
class AccountService { public function moveFunds(Account $from,Account $to,float $usd=0,float $ves=0,string $reference=null){ DB::transaction(function() use($from,$to,$usd,$ves,$reference){ if($usd>0){$from->decrement('balance_usd',$usd); $to->increment('balance_usd',$usd);} if($ves>0){$from->decrement('balance_ves',$ves); $to->increment('balance_ves',$ves);} AccountMovement::create(['account_id'=>$from->id,'type'=>'transfer_out','amount_usd'=>$usd,'amount_ves'=>$ves,'reference'=>$reference,'user_id'=>auth()->id(),'meta'=>['to'=>$to->id]]); AccountMovement::create(['account_id'=>$to->id,'type'=>'transfer_in','amount_usd'=>$usd,'amount_ves'=>$ves,'reference'=>$reference,'user_id'=>auth()->id(),'meta'=>['from'=>$from->id]]); }); }}
